198	/// Returns full agent info with state for all agents.
199	async fn list_agents(State(state): State<AppState>) -> Json<Vec<AgentInfo>> {
200	    let pending: Vec<_> = {
201	        let mgr = state.manager.lock().await;
202	        mgr.agent_ids()
203	            .iter()
204	            .filter_map(|id| {
205	                mgr.get_session(id).ok().map(|session| {
206	                    (
207	                        id.0.clone(),
208	                        session.name().to_string(),
209	                        session.role().to_string(),
210	                        session.state(),
211	                    )
212	                })
213	            })
214	            .collect()
215	    };
216	    let mut agents = Vec::with_capacity(pending.len());
217	    for (id, name, role, state_lock) in pending {
218	        let s = state_lock.read().await;
219	        agents.push(AgentInfo {
220	            id,
221	            name,
222	            role,
223	            state: s.clone(),
224	        });
225	    }
226	    Json(agents)
227	}
228	
229	/// Returns current state for a single agent.
230	async fn agent_state(
231	    Path(id): Path<String>,
232	    State(state): State<AppState>,
233	) -> Result<Json<AgentInfo>, StatusCode> {
234	    let agent_id = AgentId(id);
235	    let (name, role, state_lock) = {
236	        let mgr = state.manager.lock().await;
237	        let session = mgr
238	            .get_session(&agent_id)
239	            .map_err(|_| StatusCode::NOT_FOUND)?;
240	        (
241	            session.name().to_string(),
242	            session.role().to_string(),
243	            session.state(),
244	        )
245	    };
246	    let s = state_lock.read().await;
247	    Ok(Json(AgentInfo {
248	        id: agent_id.0,
249	        name,
250	        role,
251	        state: s.clone(),
252	    }))
253	}
254	
255	async fn agent_sse(
256	    Path(id): Path<String>,
257	    State(state): State<AppState>,
258	) -> Result<Sse<impl futures_core::Stream<Item = Result<Event, Infallible>>>, StatusCode> {
259	    let agent_id = AgentId(id);
260	    let mgr = state.manager.lock().await;
261	    let session = mgr
262	        .get_session(&agent_id)
263	        .map_err(|_| StatusCode::NOT_FOUND)?;
264	    let rx = session.output_receiver();
265	    drop(mgr);
266	
267	    let stream =
268	        tokio_stream::wrappers::BroadcastStream::new(rx).filter_map(|result| match result {
269	            Ok(OutputSignal::Bytes(bytes)) => {
270	                let b64 = base64::engine::general_purpose::STANDARD.encode(&bytes);
271	                Some(Ok(Event::default().data(b64)))
272	            }
273	            _ => None,
274	        });
275	
276	    Ok(Sse::new(stream).keep_alive(KeepAlive::default()))
277	}
