279	async fn agent_input(
280	    Path(id): Path<String>,
281	    State(state): State<AppState>,
282	    Json(payload): Json<InputPayload>,
283	) -> Result<StatusCode, StatusCode> {
284	    let agent_id = AgentId(id);
285	    let tx = {
286	        let mgr = state.manager.lock().await;
287	        let session = mgr
288	            .get_session(&agent_id)
289	            .map_err(|_| StatusCode::NOT_FOUND)?;
290	        session.input_sender()
291	    };
292	    tx.send(InputEvent::HumanText {
293	        text: payload.text,
294	    })
295	    .await
296	    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
297	    Ok(StatusCode::OK)
298	}
