300	async fn agent_ctrl_c(
301	    Path(id): Path<String>,
302	    State(state): State<AppState>,
303	) -> Result<StatusCode, StatusCode> {
304	    let agent_id = AgentId(id);
305	    let tx = {
306	        let mgr = state.manager.lock().await;
307	        let session = mgr
308	            .get_session(&agent_id)
309	            .map_err(|_| StatusCode::NOT_FOUND)?;
310	        session.input_sender()
311	    };
312	    tx.send(InputEvent::RawBytes {
313	        bytes: vec![0x03],
314	    })
315	    .await
316	    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
317	    Ok(StatusCode::OK)
318	}
