327	/// Get a wiki page by title. Returns JSON with ETag header.
328	async fn wiki_get_page(
329	    Path(title): Path<String>,
330	    State(state): State<AppState>,
331	) -> Result<Response, StatusCode> {
332	    let page = state
333	        .wiki
334	        .get_page(&title)
335	        .await
336	        .ok_or(StatusCode::NOT_FOUND)?;
337	
338	    let etag = content_etag(&page.content);
339	    let html = render_wiki_content(&page.content);
340	    let body = WikiPageResponse {
341	        title: page.title,
342	        content: page.content,
343	        html,
344	        created_at: page.created_at,
345	        updated_at: page.updated_at,
346	    };
347	
348	    let mut response = Json(body).into_response();
349	    response
350	        .headers_mut()
351	        .insert("ETag", etag.parse().unwrap());
352	    Ok(response)
353	}
354	
355	/// Create or update a wiki page. Requires If-Match header for existing pages.
356	async fn wiki_put_page(
357	    Path(title): Path<String>,
358	    headers: HeaderMap,
359	    State(state): State<AppState>,
360	    Json(body): Json<WikiPutBody>,
361	) -> Result<Response, Response> {
362	    let existing = state.wiki.get_page(&title).await;
363	    let now = wiki_common::time::now();
364	    let is_update = existing.is_some();
365	    let prev_created_at = existing.as_ref().map(|p| p.created_at);
366	
367	    if let Some(ref page) = existing {
368	        let current_etag = content_etag(&page.content);
369	        let if_match = headers
370	            .get("If-Match")
371	            .and_then(|v| v.to_str().ok())
372	            .map(|s| s.to_string());
373	
374	        match if_match {
375	            None => {
376	                return Err(conflict_response(page, &current_etag));
377	            }
378	            Some(provided) if provided != current_etag => {
379	                return Err(conflict_response(page, &current_etag));
380	            }
381	            _ => {}
382	        }
383	    }
384	
385	    let created_at = prev_created_at.unwrap_or(now);
386	    let page = WikiPage {
387	        title: title.clone(),
388	        content: body.content.clone(),
389	        created_at,
390	        updated_at: now,
391	    };
392	    state.wiki.save_page(page).await;
393	
394	    let etag = content_etag(&body.content);
395	    let html = render_wiki_content(&body.content);
396	    let resp = WikiPageResponse {
397	        title,
398	        content: body.content,
399	        html,
400	        created_at,
401	        updated_at: now,
402	    };
403	
404	    let mut response = Json(resp).into_response();
405	    response
406	        .headers_mut()
407	        .insert("ETag", etag.parse().unwrap());
408	    *response.status_mut() = if is_update {
409	        StatusCode::OK
410	    } else {
411	        StatusCode::CREATED
412	    };
413	    Ok(response)
414	}
415	
416	/// Patch a wiki page using structured operations. Requires If-Match or etag in body.
417	async fn wiki_patch_page(
418	    Path(title): Path<String>,
419	    State(state): State<AppState>,
420	    Json(patch): Json<PatchRequest>,
421	) -> Result<Response, Response> {
422	    let page = state
423	        .wiki
424	        .get_page(&title)
425	        .await
426	        .ok_or_else(|| StatusCode::NOT_FOUND.into_response())?;
427	
428	    let current_etag = content_etag(&page.content);
429	    if patch.etag != current_etag {
430	        return Err(conflict_response(&page, &current_etag));
431	    }
432	
433	    let new_content = apply_ops(&page.content, &patch.ops).map_err(|e| {
434	        (
435	            StatusCode::UNPROCESSABLE_ENTITY,
436	            Json(serde_json::json!({ "error": "patch failed", "op_index": e.op_index, "match_str": e.match_str })),
437	        )
438	            .into_response()
439	    })?;
440	
441	    let now = wiki_common::time::now();
442	    let updated = WikiPage {
443	        title: title.clone(),
444	        content: new_content.clone(),
445	        created_at: page.created_at,
446	        updated_at: now,
447	    };
448	    state.wiki.save_page(updated).await;
449	
450	    let etag = content_etag(&new_content);
451	    let html = render_wiki_content(&new_content);
452	    let resp = WikiPageResponse {
453	        title,
454	        content: new_content,
455	        html,
456	        created_at: page.created_at,
457	        updated_at: now,
458	    };
459	
460	    let mut response = Json(resp).into_response();
461	    response
462	        .headers_mut()
463	        .insert("ETag", etag.parse().unwrap());
464	    Ok(response)
465	}
466	
467	/// Delete a wiki page. Requires If-Match header.
468	async fn wiki_delete_page(
469	    Path(title): Path<String>,
470	    headers: HeaderMap,
471	    State(state): State<AppState>,
472	) -> Result<StatusCode, Response> {
473	    let page = state
474	        .wiki
475	        .get_page(&title)
476	        .await
477	        .ok_or(StatusCode::NOT_FOUND.into_response())?;
478	
479	    let current_etag = content_etag(&page.content);
480	    let if_match = headers
481	        .get("If-Match")
482	        .and_then(|v| v.to_str().ok())
483	        .map(|s| s.to_string());
484	
485	    match if_match {
486	        None => return Err(conflict_response(&page, &current_etag)),
487	        Some(provided) if provided != current_etag => {
488	            return Err(conflict_response(&page, &current_etag));
489	        }
490	        _ => {}
491	    }
492	
493	    state.wiki.delete_page(&title).await;
494	    Ok(StatusCode::NO_CONTENT)
495	}
496	
497	/// Build a 409 Conflict response with current page state.
498	fn conflict_response(page: &WikiPage, current_etag: &str) -> Response {
499	    let body = WikiConflictResponse {
500	        error: "ETag mismatch — page was modified".to_string(),
501	        current_etag: current_etag.to_string(),
502	        page: WikiPageResponse {
503	            title: page.title.clone(),
504	            content: page.content.clone(),
505	            html: render_wiki_content(&page.content),
506	            created_at: page.created_at,
507	            updated_at: page.updated_at,
508	        },
509	    };
510	    let mut resp = Json(body).into_response();
511	    *resp.status_mut() = StatusCode::CONFLICT;
512	    resp.headers_mut()
513	        .insert("ETag", current_etag.parse().unwrap());
514	    resp
515	}
516	
517	// ── Event log handlers ─────────────────────────────────────────────────
518	
519	/// List event log entries. Optional `?since=N` returns entries after index N.
520	async fn list_events(
521	    Query(query): Query<EventLogQuery>,
522	    State(state): State<AppState>,
523	) -> Json<Vec<EventLogEntry>> {
524	    let log = state.event_log.lock().await;
525	    let since = query.since.unwrap_or(0);
526	    Json(log.iter().skip(since).cloned().collect())
527	}
528	
529	/// Submit a push event for routing (e.g., from the UI or an external tool).
530	async fn submit_event(
531	    State(_state): State<AppState>,
532	    Json(body): Json<SubmitEventBody>,
533	) -> StatusCode {
534	    let event = body.event;
535	
536	    // Write the event to the source agent's outbox as a JSON file.
537	    let outbox_dir = PathBuf::from(".atn")
538	        .join("outboxes")
539	        .join(&event.source_agent);
540	    let _ = tokio::fs::create_dir_all(&outbox_dir).await;
541	    let file_path = outbox_dir.join(format!("{}.json", event.id));
542	    if let Ok(json) = serde_json::to_string_pretty(&event) {
543	        let _ = tokio::fs::write(&file_path, json).await;
544	    }
545	
546	    // The background router will pick it up on next poll.
547	    StatusCode::ACCEPTED
548	}
