#[derive(Clone)]
struct SharedState {
    manager: Arc<Mutex<SessionManager>>,
    wiki: Arc<FileWikiStorage>,
    event_log: router::EventLog,
}

type AppState = SharedState;

static INDEX_HTML: &str = include_str!("../static/index.html");

const DEFAULT_CONFIG_PATH: &str = "agents.toml";

#[derive(Deserialize)]
